-- H5.41 - Sincronização offline, versionamento e colunas JSON geradas
-- Rode após 012. Script defensivo para HostGator/MySQL/MariaDB.

CREATE TABLE IF NOT EXISTS sync_actions (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT PRIMARY KEY,
  client_uuid VARCHAR(80) NULL,
  tabela VARCHAR(80) NOT NULL,
  entidade_id VARCHAR(80) NULL,
  operacao VARCHAR(20) NOT NULL,
  status VARCHAR(30) NOT NULL,
  usuario_id VARCHAR(64) NULL,
  payload LONGTEXT NULL,
  criado_em DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_sync_uuid (client_uuid),
  INDEX idx_sync_status (status),
  INDEX idx_sync_entidade (tabela, entidade_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SET @db := DATABASE();

-- Colunas de sync/optimistic locking nas tabelas operacionais.
SET @tables := 'viagens,veiculos,pacientes,passageiros,despesas,ocorrencias,alertas,mensagens,checklists,eventos,localizacoes,destinos';

-- viagens
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='viagens' AND COLUMN_NAME='client_uuid')=0,
  'ALTER TABLE viagens ADD COLUMN client_uuid VARCHAR(80) NULL', 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='viagens' AND COLUMN_NAME='client_timestamp')=0,
  'ALTER TABLE viagens ADD COLUMN client_timestamp DATETIME NULL', 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='viagens' AND COLUMN_NAME='version')=0,
  'ALTER TABLE viagens ADD COLUMN version INT UNSIGNED NOT NULL DEFAULT 1', 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

