-- Colunas geradas por JSON para consulta rápida sem migrar metadados TEXT para JSON rígido.
-- Usa JSON_VALID para não quebrar registros antigos com metadados inválidos.
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='localizacoes' AND COLUMN_NAME='temperatura_c')=0,
  "ALTER TABLE localizacoes ADD COLUMN temperatura_c DECIMAL(5,2) GENERATED ALWAYS AS (CAST(CASE WHEN JSON_VALID(metadados) THEN JSON_UNQUOTE(JSON_EXTRACT(metadados, '$.temperatura_c')) ELSE NULL END AS DECIMAL(5,2))) VIRTUAL", 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='localizacoes' AND INDEX_NAME='idx_localizacoes_temp')=0,
  'ALTER TABLE localizacoes ADD INDEX idx_localizacoes_temp (temperatura_c)', 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;

SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='eventos' AND COLUMN_NAME='temp_max_c')=0,
  "ALTER TABLE eventos ADD COLUMN temp_max_c DECIMAL(5,2) GENERATED ALWAYS AS (CAST(CASE WHEN JSON_VALID(metadados) THEN JSON_UNQUOTE(JSON_EXTRACT(metadados, '$.temp_max')) ELSE NULL END AS DECIMAL(5,2))) VIRTUAL", 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
SET @sql := IF((SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS WHERE TABLE_SCHEMA=@db AND TABLE_NAME='eventos' AND INDEX_NAME='idx_eventos_temp_max')=0,
  'ALTER TABLE eventos ADD INDEX idx_eventos_temp_max (temp_max_c)', 'SELECT 1'); PREPARE stmt FROM @sql; EXECUTE stmt; DEALLOCATE PREPARE stmt;
